import{_ as a,o as e,c as d,a2 as r}from"./chunks/framework.Cr-Z7ngm.js";const u=JSON.parse('{"title":"资产设置","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"portfolio-and-statements/settings.md","filePath":"zh-CN/portfolio-and-statements/settings.md"}'),o={name:"portfolio-and-statements/settings.md"};function h(i,t,l,n,s,b){return e(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="资产设置" tabindex="-1">资产设置 <a class="header-anchor" href="#资产设置" aria-label="Permalink to &quot;资产设置&quot;">​</a></h1><p>资产设置用于自定义持仓列表的显示方式、成本计算方法和价格来源偏好。</p><h2 id="页面入口" tabindex="-1">页面入口 <a class="header-anchor" href="#页面入口" aria-label="Permalink to &quot;页面入口&quot;">​</a></h2><p>资产页 → 全部功能 → 资产设置，或资产页右上角设置图标。</p><hr><h2 id="股票名称代码显示" tabindex="-1">股票名称代码显示 <a class="header-anchor" href="#股票名称代码显示" aria-label="Permalink to &quot;股票名称代码显示&quot;">​</a></h2><p>控制持仓列表、关注列表、订单等页面中股票条目的排列方式。</p><table tabindex="0"><thead><tr><th>选项</th><th>显示效果</th></tr></thead><tbody><tr><td>股票名称在上</td><td>名称（如「腾讯控股」）显示在第一行，代码（如「00700 · HK」）在第二行</td></tr><tr><td>股票代码在上</td><td>代码（如「00700 · HK」）显示在第一行，名称在第二行</td></tr></tbody></table><blockquote><p>该设置会影响关注列表、持仓、订单等页面布局。</p></blockquote><hr><h2 id="成本计算方式" tabindex="-1">成本计算方式 <a class="header-anchor" href="#成本计算方式" aria-label="Permalink to &quot;成本计算方式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>选项</th><th>说明</th></tr></thead><tbody><tr><td>摊薄成本</td><td>包含历史所有买卖摊薄后的平均成本，反映整体持仓成本</td></tr><tr><td>平均开仓成本</td><td>仅以当前持有数量的买入均价计算，不含历史卖出影响</td></tr></tbody></table><hr><h2 id="价格计算方式" tabindex="-1">价格计算方式 <a class="header-anchor" href="#价格计算方式" aria-label="Permalink to &quot;价格计算方式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>选项</th><th>说明</th></tr></thead><tbody><tr><td>美股使用盘前盘后价</td><td>盈亏计算参考美股延长时段（盘前/盘后）的最新成交价</td></tr><tr><td>美股使用夜盘价</td><td>盈亏计算参考夜盘价格，今日盈亏将在美东时间 20:00 重新计算</td></tr><tr><td>期权使用延长时段价格</td><td>期权持仓盈亏参考延长时段价格计算</td></tr></tbody></table><hr><h2 id="持仓列表展示" tabindex="-1">持仓列表展示 <a class="header-anchor" href="#持仓列表展示" aria-label="Permalink to &quot;持仓列表展示&quot;">​</a></h2><h3 id="持仓分布表头设置" tabindex="-1">持仓分布表头设置 <a class="header-anchor" href="#持仓分布表头设置" aria-label="Permalink to &quot;持仓分布表头设置&quot;">​</a></h3><p>自定义持仓列表各列显示的数据字段（如当日盈亏、持仓成本、市值等）。</p><h3 id="期权表头设置" tabindex="-1">期权表头设置 <a class="header-anchor" href="#期权表头设置" aria-label="Permalink to &quot;期权表头设置&quot;">​</a></h3><p>单独配置期权持仓列表的列头字段。</p><h3 id="持仓显示设置" tabindex="-1">持仓显示设置 <a class="header-anchor" href="#持仓显示设置" aria-label="Permalink to &quot;持仓显示设置&quot;">​</a></h3><table tabindex="0"><thead><tr><th>选项</th><th>说明</th></tr></thead><tbody><tr><td>显示当日清仓标的</td><td>开启后，当天已卖出清仓的持仓仍显示在列表中</td></tr><tr><td>显示已退市持仓</td><td>开启后，已退市或停牌的标的持续显示</td></tr><tr><td>同标的正股衍生品合并展示</td><td>开启后，同一正股和其衍生品（期权、窝轮等）合并为一条记录，点击展开查看明细</td></tr></tbody></table>',23)])])}const p=a(o,[["render",h]]);export{u as __pageData,p as default};
